lemma FlattenSingleton(x: string)
  ensures Flatten([x]) == x
{
  assert [x][..0] == [];
  assert [x][0] == x;
}

lemma FlattenPair(a: string, b: string)
  ensures Flatten([a, b]) == a + b
{
  assert [a, b][..1] == [a];
  assert [a, b][1] == b;
  FlattenSingleton(a);
}

// New lemma to prove that substrings of binary strings are binary
lemma SubstringIsBinary(s: string, i: int, j: int)
  requires 0 <= i <= j <= |s|
  requires IsBinaryString(s)
  ensures IsBinaryString(s[i..j])
{
  forall k | 0 <= k < j - i {
    var pos := i + k;
    assert 0 <= pos < |s|;
    assert s[pos] == '0' || s[pos] == '1';
    assert s[i..j][k] == s[pos];
  }
}

// New lemma to prove that odd-length binary strings have unequal counts
lemma OddLengthImpliesNotEqualCounts(s: string)
  requires IsBinaryString(s)
  requires |s| % 2 == 1
  ensures IsGood(s)
{
  CountCharSum(s);
  var sum := CountChar(s, '0') + CountChar(s, '1');
  assert sum == |s|;
  assert sum % 2 == 1;
  // If counts were equal, sum would be even. But sum is odd. Contradiction.
  assert (CountChar(s, '0') == CountChar(s, '1')) ==> (sum % 2 == 0);
  assert sum % 2 == 1 ==> (sum % 2 != 0);
  assert (CountChar(s, '0') == CountChar(s, '1')) ==> false;
  assert CountChar(s, '0') != CountChar(s, '1');
}

